const MM_TO_M3_PER_SQKM = 1000;
const LITERS_TO_M3 = 0.001;
const AVG_DAYS_PER_MONTH = 30.437;

// Input validation and default handling
const catchmentAreaSqKm = Math.max(0.1, inputs.catchmentAreaSqKm || 0.1);
const currentSnowpackSWE = Math.max(0, inputs.currentSnowpackSWE || 0);
const predictedRainfall = Math.max(0, inputs.predictedRainfall || 0);
const historicalAvgPrecipitation = Math.max(0, inputs.historicalAvgPrecipitation || 0);
const historicalAvgSnowpackSWE = Math.max(0, inputs.historicalAvgSnowpackSWE || 0);
const regionalConsumptionRatePerCapita = Math.max(0, inputs.regionalConsumptionRatePerCapita || 0);
const regionalPopulation = Math.max(1, inputs.regionalPopulation || 1);
const projectionDurationMonths = Math.max(1, inputs.projectionDurationMonths || 1);
const evapotranspirationFactor = Math.min(Math.max(0, inputs.evapotranspirationFactor || 0), 0.9);

// 1. Calculate Gross Water Input from Current Conditions
const totalCurrentPrecipitation_mm = currentSnowpackSWE + predictedRainfall;
const grossCurrentSupply_m3 = totalCurrentPrecipitation_mm * catchmentAreaSqKm * MM_TO_M3_PER_SQKM;

// 2. Adjust for Evapotranspiration Losses
const evapLoss_m3 = grossCurrentSupply_m3 * evapotranspirationFactor;
const netCurrentSupply_m3 = Math.max(0, grossCurrentSupply_m3 - evapLoss_m3);

// 3. Calculate Historical Average Water Supply
const totalHistoricalPrecipitation_mm = historicalAvgSnowpackSWE + historicalAvgPrecipitation;
const historicalAvgSupply_m3 = totalHistoricalPrecipitation_mm * catchmentAreaSqKm * MM_TO_M3_PER_SQKM;

// Handle zero historical average to prevent division by zero or unrealistic comparisons
const effectiveHistoricalAvgSupply_m3 = historicalAvgSupply_m3 > 0 ? historicalAvgSupply_m3 : 1; // Use 1 to avoid division by zero, though in practice it should be >0 for a real region.

// 4. Calculate Total Regional Water Consumption for Projection Period
const dailyRegionalConsumption_liters = regionalConsumptionRatePerCapita * regionalPopulation;
const totalConsumption_liters = dailyRegionalConsumption_liters * projectionDurationMonths * AVG_DAYS_PER_MONTH;
const totalConsumption_m3 = totalConsumption_liters * LITERS_TO_M3;

// 5. Determine Projected Water Balance (Surplus/Deficit)
const projectedWaterSurplusDeficit_m3 = netCurrentSupply_m3 - totalConsumption_m3;

// 6. Calculate Projected Supply as Percentage of Historical Average
let percentageOfHistoricalAverage = (netCurrentSupply_m3 / effectiveHistoricalAvgSupply_m3) * 100;
if (historicalAvgSupply_m3 === 0) percentageOfHistoricalAverage = 0; // If historical average is truly zero, then current supply is effectively 0% of that.

// 7. Assess Drought Risk Category
let droughtRiskCategory = 'Data Insufficient'; // Default for extreme cases

if (effectiveHistoricalAvgSupply_m3 > 0) {
    if (percentageOfHistoricalAverage >= 95 && projectedWaterSurplusDeficit_m3 >= 0) {
        droughtRiskCategory = 'Low Risk (Surplus Expected)';
    } else if (percentageOfHistoricalAverage >= 80 && projectedWaterSurplusDeficit_m3 >= 0) {
        droughtRiskCategory = 'Low Risk (Sufficient)';
    } else if (percentageOfHistoricalAverage >= 70 && projectedWaterSurplusDeficit_m3 >= 0) {
        droughtRiskCategory = 'Moderate Risk (Approaching Deficit)';
    } else if (percentageOfHistoricalAverage >= 70 && projectedWaterSurplusDeficit_m3 < 0) {
        droughtRiskCategory = 'Moderate Risk (Minor Deficit Expected)';
    } else if (percentageOfHistoricalAverage >= 50) {
        droughtRiskCategory = 'High Risk (Significant Deficit Likely)';
    } else if (percentageOfHistoricalAverage < 50) {
        droughtRiskCategory = 'Severe Drought (Critical Shortage)';
    } else {
        droughtRiskCategory = 'Undefined Risk'; // Fallback
    }
} else if (projectedWaterSurplusDeficit_m3 < 0) {
    droughtRiskCategory = 'Severe Drought (Zero Historical Supply, Current Deficit)';
} else {
    droughtRiskCategory = 'Low Risk (Zero Historical Supply, Current Surplus)';
}

return {
  projectedWaterSurplusDeficit_m3: projectedWaterSurplusDeficit_m3,
  percentageOfHistoricalAverage: percentageOfHistoricalAverage,
  droughtRiskCategory: droughtRiskCategory
};
